// 1. Buat larik angka
const angka = [];

// 2. Urutkan dari terkecil ke terbesar (ascending)
// Gunakan .sort() dengan fungsi pembanding (a - b)

// 3. Urutkan dari terbesar ke terkecil (descending)
// Gunakan .sort() dengan fungsi pembanding (b - a)

// 4. Tampilkan hasil
// console.log('Naik: ' + ...);
// console.log('Turun: ' + ...);

solution:
const angka = [5, 2, 9, 1, 7, 3];

const naik = [...angka].sort(function(a, b) {
  return a - b;
});
console.log('Naik: ' + naik.join(', '));

const turun = [...angka].sort(function(a, b) {
  return b - a;
});
console.log('Turun: ' + turun.join(', '));
